import React from 'react';
import { ICONS, Icon } from '../shared';

const LOGO = "data:image/png;base64,";

const NAV = [
  { id: 'dashboard',    label: 'Dashboard',        icon: ICONS.home },
  { id: 'stock',        label: 'Stock',             icon: ICONS.box },
  { id: 'cargar-stock', label: 'Cargar Stock',      icon: ICONS.upload },
  { id: 'ventas',       label: 'Ventas',            icon: ICONS.cart },
  { id: 'codigos',      label: 'Códigos de Barras', icon: ICONS.barChart },
  { id: 'facturacion',  label: 'Facturación',       icon: ICONS.file },
];

export default function Sidebar({ section, setSection, children }) {
  const today = new Date().toLocaleDateString('es-AR', { weekday: 'long', day: 'numeric', month: 'long' });

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: '#fafafa' }}>
      <aside style={{ width: 220, background: '#fff', borderRight: '1px solid rgba(0,0,0,0.06)',
        boxShadow: '2px 0 20px rgba(0,0,0,0.02)',
        display: 'flex', flexDirection: 'column', position: 'fixed', top: 0, bottom: 0, left: 0, zIndex: 100 }}>

        {/* Logo */}
        <div style={{ padding: '30px 24px 20px', borderBottom: '1px solid rgba(0,0,0,0.04)',
          display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
          <img
            src={LOGO}
            alt="SolSur"
            style={{ width: 70, height: 70, objectFit: 'contain', opacity: 0.9 }}
          />
          <div style={{ fontSize: 9, letterSpacing: 3, color: '#999', textTransform: 'uppercase', marginTop: 12, fontWeight: 400 }}>
            Sistema de Gestión
          </div>
        </div>

        {/* Nav */}
        <nav style={{ flex: 1, padding: '12px 0', overflowY: 'auto' }}>
          {NAV.map(({ id, label, icon }) => {
            const active = section === id;
            return (
              <button key={id} onClick={() => setSection(id)} style={{
                width: '100%', display: 'flex', alignItems: 'center', gap: 12,
                padding: '12px 24px', border: 'none', borderRadius: 0, cursor: 'pointer',
                background: active ? '#fafafa' : 'transparent',
                color: active ? '#2c2c2c' : '#888',
                fontWeight: active ? 400 : 300,
                fontSize: 13, letterSpacing: 1, fontFamily: 'inherit',
                transition: 'all 0.25s ease',
                borderLeft: active ? '3px solid #2c2c2c' : '3px solid transparent',
              }}
                onMouseEnter={e => { if (!active) e.currentTarget.style.background = '#fafafa'; }}
                onMouseLeave={e => { if (!active) e.currentTarget.style.background = 'transparent'; }}
              >
                <Icon path={icon} size={15} />
                {label}
              </button>
            );
          })}
        </nav>

        {/* Date */}
        <div style={{ padding: '16px 24px', borderTop: '1px solid rgba(0,0,0,0.04)' }}>
          <div style={{ fontSize: 10, color: '#aaa', letterSpacing: 1, textTransform: 'capitalize', fontWeight: 300 }}>{today}</div>
        </div>
      </aside>

      {/* Main */}
      <main style={{ marginLeft: 220, flex: 1, padding: '36px 40px', minHeight: '100vh' }}>
        {children}
      </main>
    </div>
  );
}
